mapper.select:
SELECT id, reward_id, buyer_id, family_id, point_transaction_id, status, notes, created_at, updated_at
FROM reward_purchases
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}

SELECT id, reward_id, buyer_id, family_id, point_transaction_id, status, notes, created_at, updated_at
FROM reward_purchases
WHERE buyer_id = #{buyerId, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
  AND status = #{status, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.RewardPurchaseStatusTypeHandler}
ORDER BY created_at DESC

mapper.update:
UPDATE reward_purchases
SET status = #{status, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.RewardPurchaseStatusTypeHandler},
    notes = #{notes},
    updated_at = #{updatedAt}
WHERE id = #{id, jdbcType=OTHER, typeHandler=com.kidspoint.api.config.UUIDTypeHandler}
